function softmax(logits) {
  const max = Math.max(...logits);
  const exps = logits.map(v => Math.exp(v - max));
  const sum = exps.reduce((a, b) => a + b, 0);
  return exps.map(v => v / sum);
}

function computeProbabilitiesFromMessages(messagesArray, labels = ["r", "c", "o"]) {
  if (!Array.isArray(messagesArray) || messagesArray.length === 0) {
    throw new Error("Input must be an array of message objects.");
  }

  const msg0 = messagesArray[0];
  const chunk = msg0?.content?.find(c => c.type === "output_text");
  if (!chunk) throw new Error("No output_text chunk found.");

  const lpEntry = chunk?.logprobs?.[0];
  if (!lpEntry) throw new Error("No logprobs found.");

  const predicted = String(chunk.text).trim();
  const logprobPred = lpEntry.logprob;

  // Absolute probability
  const p_token = Math.exp(logprobPred);

  // Try to compute normalized class probability
  const top = lpEntry.top_logprobs || [];
  const labelToLogprob = new Map();

  for (const t of top) {
    const tok = String(t.token).trim();
    if (labels.includes(tok)) labelToLogprob.set(tok, t.logprob);
  }

  if (labels.includes(predicted) && !labelToLogprob.has(predicted)) {
    labelToLogprob.set(predicted, logprobPred);
  }

  const available = labels.filter(l => labelToLogprob.has(l));

  let p_class_normalized = null;
  let class_probs = Object.fromEntries(labels.map(l => [l, null]));

  if (available.length === labels.length) {
    const logits = labels.map(l => labelToLogprob.get(l));
    const probs = softmax(logits);
    labels.forEach((l, i) => (class_probs[l] = probs[i]));
    p_class_normalized = class_probs[predicted];
  }

  return {
    predicted,
    logprob: logprobPred,
    p_token,
    p_class_normalized,
    class_probs
  };
}

// ✅ In "Run Once for Each Item" mode:
const messagesArray = $json.output;

const result = computeProbabilitiesFromMessages(messagesArray);

// Return one item
return {
  json: result
};

